<?php
namespace App\Models\Customers; use Illuminate\Database\Eloquent\Attributes\Fillable; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\HasMany;
#[Fillable(['company_id','customer_id','loyalty_number','tier','points_balance','lifetime_points_earned','lifetime_points_redeemed','joined_at','last_activity_at','is_active'])] class CustomerLoyaltyAccount extends Model {protected function casts():array{return ['joined_at'=>'datetime','last_activity_at'=>'datetime','is_active'=>'boolean'];} public function customer():BelongsTo{return $this->belongsTo(Customer::class);} public function transactions():HasMany{return $this->hasMany(CustomerLoyaltyTransaction::class,'loyalty_account_id')->latest();}}
